import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { ExternalLink } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import ExternalLinkConfirmDialog from "@/components/ExternalLinkConfirmDialog";
import { useIsMobile } from "@/hooks/use-mobile";

interface Ad {
  id: string;
  name: string;
  image_url: string | null;
  mobile_image_url: string | null;
  desktop_image_url: string | null;
  link_url: string | null;
  is_active: boolean;
  sort_order: number;
  start_date: string | null;
  end_date: string | null;
}

const adsTable = () => (supabase as any).from("ads");

const RecipeAds = () => {
  const { t } = useTranslation();
  const isMobile = useIsMobile();
  const [pendingUrl, setPendingUrl] = useState<string | null>(null);
  const [pendingAdName, setPendingAdName] = useState<string | null>(null);

  const { data: ads } = useQuery({
    queryKey: ["active-ads"],
    queryFn: async () => {
      const now = new Date().toISOString();
      const { data, error } = await adsTable()
        .select("*")
        .eq("is_active", true)
        .or(`start_date.is.null,start_date.lte.${now}`)
        .or(`end_date.is.null,end_date.gte.${now}`)
        .order("sort_order", { ascending: true });
      if (error) throw error;
      return data as Ad[];
    },
    staleTime: 5 * 60 * 1000,
  });

  if (!ads || ads.length === 0) return null;

  const handleAdClick = (ad: Ad) => {
    if (ad.link_url) {
      setPendingUrl(ad.link_url);
      setPendingAdName(ad.name);
    }
  };

  const handleConfirm = () => {
    if (pendingUrl) {
      window.open(pendingUrl, "_blank", "noopener,noreferrer");
      setPendingUrl(null);
      setPendingAdName(null);
    }
  };

  const getImageUrl = (ad: Ad) => {
    if (isMobile) {
      return ad.mobile_image_url || ad.desktop_image_url || ad.image_url;
    }
    return ad.desktop_image_url || ad.mobile_image_url || ad.image_url;
  };

  return (
    <>
      <div className="space-y-2 mt-3">
        {ads.map((ad) => {
          const imgUrl = getImageUrl(ad);
          return (
            <div
              key={ad.id}
              className="relative rounded-lg overflow-hidden border border-border/50 hover:border-primary/30 transition-colors cursor-pointer"
              style={{ aspectRatio: isMobile ? '375/112' : '672/112' }}
              onClick={() => handleAdClick(ad)}
            >
              {/* Ad label */}
              <Badge className="absolute top-1.5 left-1.5 z-10 bg-black/60 text-white text-[10px] px-1.5 py-0.5 rounded hover:bg-black/60">
                {t("common.ad", "广告")}
              </Badge>

              {imgUrl ? (
                <img
                  src={imgUrl}
                  alt={ad.name}
                  className="w-full h-full object-cover"
                />
              ) : (
                <div className="flex items-center gap-2 px-3 bg-muted/50 text-sm text-muted-foreground w-full h-full justify-center">
                  <ExternalLink className="h-3.5 w-3.5 shrink-0" />
                  <span className="truncate">{ad.name}</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <ExternalLinkConfirmDialog
        open={!!pendingUrl}
        onOpenChange={(open) => { if (!open) { setPendingUrl(null); setPendingAdName(null); } }}
        onConfirm={handleConfirm}
        url={pendingUrl || undefined}
        title={t("common.adLinkTitle", "外部链接")}
        description={t("common.adLinkDescription", "您即将离开本站，前往广告链接「{{name}}」的外部页面", { name: pendingAdName || "" })}
        confirmLabel={t("common.adLinkContinue", "继续前往")}
      />
    </>
  );
};

export default RecipeAds;
